export const listFeedResponseDataItemCommentCountMin = 0;

export const listFeedResponseDataItemShareCountMin = 0;

export const ListFeedResponse = zod.object({
  data: zod.array(
    zod.object({
      id: zod.string().uuid(),
      postType: zod.enum(["short", "long"]),
      title: zod.string().nullish(),
      description: zod.string().nullish(),
      body: zod.string().nullish(),
      bodyTruncated: zod
        .boolean()
        .describe(
          "True when description or body was truncated in the feed page",
        ),
      isEdited: zod.boolean(),
      createdAt: zod.coerce.date(),
      updatedAt: zod.coerce.date().optional(),
      author: zod.object({
        id: zod.string().uuid(),
        displayName: zod.string(),
        avatarUrl: zod.string().nullable(),
      }),
      context: zod.object({
        type: zod.enum(["user", "organization", "team"]),
        id: zod.string().uuid(),
        name: zod.string().nullish(),
        slug: zod.string().nullish(),
        orgSlug: zod.string().nullish(),
        orgId: zod
          .string()
          .uuid()
          .nullish()
          .describe(
            "Parent org id for team contexts only; enables linking to the org page.",
          ),
        orgName: zod
          .string()
          .nullish()
          .describe("Parent org display name for team contexts only."),
        avatarUrl: zod.string().nullish(),
      }),
      assets: zod.array(
        zod.object({
          id: zod.string().uuid(),
          fileType: zod.string(),
          url: zod.string().url(),
          displayOrder: zod
            .number()
            .min(listFeedResponseDataItemAssetsItemDisplayOrderMin),
        }),
      ),
      reactionCount: zod.number().min(listFeedResponseDataItemReactionCountMin),
      hasReacted: zod.boolean(),
      commentCount: zod.number().min(listFeedResponseDataItemCommentCountMin),
      recentReactorName: zod
        .string()
        .nullish()
        .describe(
          'Display name of the most recent reactor, for \"X and N others reacted\" UI.',
        ),
      shareCount: zod
        .number()
        .min(listFeedResponseDataItemShareCountMin)
        .optional()
        .describe(
          "Re-share count for game-recap articles and highlights; always 0 for org posts.",
        ),
      hasShared: zod
        .boolean()
        .optional()
        .describe("True when the requesting user has re-shared this post."),
      sharedBy: zod
        .object({
          id: zod.string().uuid(),
          displayName: zod.string(),
          avatarUrl: zod.string().nullable(),
        })
        .nullish()
        .describe(
          "Set when this card represents a re-share visible to the\nviewer (the share comes from the viewer or someone they\nfollow). The card's `author` and `context` describe the\noriginal recap or highlight.\n",
        ),
      sharedAt: zod.coerce
        .date()
        .nullish()
        .describe(
          "ISO datetime the share was created; only set when `sharedBy` is set.",
        ),
      gameDate: zod.coerce
        .date()
        .nullish()
        .describe(
          "For long-form game-recap article cards, the date of the\ngame the recap covers. Null on non-recap article cards\nand on highlight \/ org-post cards. Per task #190 the\nclient allows sharing both recaps (article + gameDate)\nand highlights; only org posts are not shareable.\n",
        ),
      canEdit: zod
        .boolean()
        .optional()
        .describe(
          'True when the requesting user is allowed to edit this\npost (author, co-author, or admin of the team\'s org).\nDrives the \"Edit post\" item in the post 3-dot menu.\nAlways false for non-article post types since the\ncomposer only edits articles.\n',
        ),
      canDelete: zod
        .boolean()
        .optional()
        .describe(
          'True when the requesting user is the original author of\nthis post (and only the original author — co-authors,\ncoaches, and org admins do not get delete access even\nwhen `canEdit` is true). Drives the \"Delete post\" item\nin the post 3-dot menu. Always false for non-article\npost types since the composer only deletes articles.\n',
        ),
    }),
  ),
  pagination: zod.object({
    nextCursor: zod.string().nullish(),
    hasMore: zod.boolean(),
    totalCount: zod.number().nullish(),
  }),
});

