/**
 * Aggregates events addressed to the child — direct notifications, tags in posts, comments on posts the child is involved with, messages in conversations the child participates in, and roster events — into a single stream for the parent. The parent's per-item read state is tracked separately from the child's, so marking items here does not change what the child sees. Pass `includeDecided=true` to also surface items the parent has already approved or removed (so they can be reviewed and undone from the "Decided" history strip).

 * @summary List the unified notification stream for a guardian-managed child
 */
export const ListChildNotificationsParams = zod.object({
  childId: zod.coerce.string().uuid(),
});

export const listChildNotificationsQueryIncludeDecidedDefault = false;

export const ListChildNotificationsQueryParams = zod.object({
  includeDecided: zod.coerce
    .boolean()
    .default(listChildNotificationsQueryIncludeDecidedDefault)
    .describe(
      "When `true`, the response includes items the parent has previously approved or removed alongside the still-undecided items. The `unreadCount` always reflects the default feed and is not inflated by decided items.\n",
    ),
});

export const ListChildNotificationsResponse = zod.object({
  data: zod.array(
    zod.object({
      itemKey: zod
        .string()
        .describe(
          "Stable key in the form `<kind>:<id>` (e.g. `tag:abc-123`). Used as the identifier when marking the item read.\n",
        ),
      kind: zod
        .enum(["notification", "tag", "comment", "message", "roster"])
        .describe(
          "Source of the aggregated item. The `itemKey` always begins with this kind followed by a colon and the underlying row's id.\n",
        ),
      title: zod.string(),
      body: zod.string().nullable(),
      link: zod
        .string()
        .nullable()
        .describe(
          "App-relative path the parent should land on when activating the item, or `null` when there is no useful destination.\n",
        ),
      isRead: zod
        .boolean()
        .describe(
          "Whether the parent has already marked this item as seen for this child. Tracked separately from the child's own read state.\n",
        ),
      decision: zod
        .enum(["approved", "removed"])
        .nullable()
        .describe(
          "The parent's recorded decision for this item, or `null` if no decision has been made yet. Items with a non-null decision drop out of the default feed on the next fetch.\n",
        ),
      createdAt: zod.coerce.date(),
      actor: zod
        .object({
          id: zod.string().uuid(),
          displayName: zod.string(),
          avatarUrl: zod.string().url().nullable(),
        })
        .nullable()
        .describe(
          "The user who triggered the underlying event (tagger, commenter, message sender). `null` for items that are not attributable to a single user (e.g. a generic notification or a roster status change).\n",
        ),
    }),
  ),
  unreadCount: zod
    .number()
    .describe("Number of items in `data` the parent has not yet marked read."),
});

/**
 * @summary Mark a single child-stream item as read for the parent
 */
export const MarkChildNotificationReadParams = zod.object({
  childId: zod.coerce.string().uuid(),
});

export const markChildNotificationReadBodyItemKeyMax = 200;

export const MarkChildNotificationReadBody = zod.object({
  itemKey: zod
    .string()
    .max(markChildNotificationReadBodyItemKeyMax)
    .describe(
      "The aggregated item's key in the form `<kind>:<id>`, e.g. `tag:abc-123` or `comment:def-456`.\n",
    ),
});

/**
 * @summary Mark every currently visible child-stream item as read
 */
export const MarkAllChildNotificationsReadParams = zod.object({
  childId: zod.coerce.string().uuid(),
});

export const MarkAllChildNotificationsReadResponse = zod.object({
  markedCount: zod
    .number()
    .describe("Number of items newly marked as read by this call."),
});

/**
 * Records an `approved` decision for every still-visible item in the child's aggregated stream. Approving does not perform any destructive action — it just records the parent's verdict so the item drops out of the default feed on the next fetch.

 * @summary Approve every still-undecided item in the child's stream
 */
export const ApproveAllChildNotificationsParams = zod.object({
  childId: zod.coerce.string().uuid(),
});

export const ApproveAllChildNotificationsResponse = zod.object({
  approvedCount: zod.number(),
});

/**
 * Records a per-item decision for the parent. `approved` only records the verdict. `removed` *also* performs the kind-specific destructive action: declining a tag, hiding a comment for the child's view of the post, hiding a message from the child's conversation view, declining a roster invite, removing a follow or reaction, or just-dismissing for unhandled notification kinds.

 * @summary Approve or remove a single child-stream item
 */
export const DecideChildNotificationParams = zod.object({
  childId: zod.coerce.string().uuid(),
});

export const DecideChildNotificationBody = zod.object({
  itemKey: zod
    .string()
    .describe(
      "The aggregated item's key in the form `<kind>:<id>`, e.g. `tag:abc-123` or `comment:def-456`.\n",
    ),
  decision: zod
    .enum(["approve", "remove", "approved", "removed"])
    .describe(
      "Action verb (`approve` \/ `remove`) or the past-tense state name (`approved` \/ `removed`). All four are accepted and normalized server-side to the state name returned in the response.\n",
    ),
});

export const DecideChildNotificationResponse = zod.object({
  ok: zod.boolean(),
  decision: zod.enum(["approved", "removed"]),
});

/**
 * Clears the parent's persisted decision for a single item so it resurfaces in the default feed as fresh and unread. For previously-removed items, the reversible kind-specific side effects are also undone (un-decline a tag, clear a comment hide, clear a message hide). Side effects that cannot be safely restored (a hard-deleted pending roster invite, a removed follow / reaction) are best-effort no-ops.

 * @summary Revert a previous Approve/Remove decision back to "needs review"
 */
export const UnsetChildNotificationDecisionParams = zod.object({
  childId: zod.coerce.string().uuid(),
});

export const UnsetChildNotificationDecisionBody = zod.object({
  itemKey: zod
    .string()
    .describe(
      "The aggregated item's key in the form `<kind>:<id>`. Must correspond to a prior decision row owned by this parent + child, otherwise a 404 is returned.\n",
    ),
});

export const UnsetChildNotificationDecisionResponse = zod.object({
  ok: zod.boolean(),
  reverted: zod.enum(["approved", "removed"]),
});

